    #[test]
    fn duplicate_functions_detected() {
        let source = r#"
fn alpha(a: i32, b: i32) -> i32 {
    let result = a + b;
    result + a
}

fn beta(x: i32, y: i32) -> i32 {
    let result = x + y;
    result + x
}
"#;
        let mut parser = tree_sitter::Parser::new();
        parser
            .set_language(&tree_sitter_rust::LANGUAGE.into())
            .unwrap();
